\`\`\`solidity pragma solidity $\mathbf { \hat { \mu } _ { \hat { \mu } } 0 . 5 . 0 } _ { \mathrm { i } }$ ; 

contract ModifierEntrancy {   
mapping (address $= >$ uint) public tokenBalance; string constant name $\mathbf { \mu } = " \mathbf { N u }$ Token";   
Bank bank;   
constructor() public{   
bank $=$ new Bank();   
} 

//If a contract has a zero balance and supports the token give them some token function airDrop() supportsToken hasNoBalance public{ // In the fixed version supportsToken comes before hasNoBalance 

tokenBalance[msg.sender] $\mathbf { + } 2 \mathbf { 0 }$ ; } 

//Checks that the contract responds the way we want   
modifier supportsToken() {   
require(keccak256(abi.encodePacked("Nu Token")) $= =$ bank.supportsToken()); _;   
}   
//Checks that the caller has a zero balance   
modifier hasNoBalance {   
require(tokenBalance[msg.sender] $\mathbf { \eta } = = \mathbf { 0 }$ );   
_;   
}   
} 

contract Bank{ 

function supportsToken() external returns(bytes32){ return(keccak256(abi.encodePacked("Nu Token"))); }   
} 

